/* eslint-disable react-refresh/only-export-components */
import React, {
  useCallback,
  useEffect,
  useMemo,
  useRef,
  useState,
} from "react";
import type { PanelProps } from "../PanelRegistry";
import { filesManager, useFilesSnapshot } from "../files-manager";
import { useRobotTelemetry } from "../use-robot-telemetry";
import { useVideoSyncSnapshot, videoSyncManager } from "../video-sync-manager";
import { SmartVideoSlider } from "./SmartVideoSlider";
import {
  ArrowLeftToLine,
  ArrowRightToLine,
  FolderOpen,
  FastForward,
  Volume2,
  VolumeX,
  Pause,
  Play,
  Rewind,
  SkipBack,
  SkipForward,
  StepBack,
  StepForward,
} from "lucide-react";

export const videoSyncPanelTags = [
  "video",
  "sync",
  "playback",
  "analysis",
  "timeline",
];

type SyncMode = "beginning" | "segment";
type TelemetryTargetMode = "packet" | "datetime";

interface SyncAnchor {
  mode: SyncMode;
  telemetryTimestamp: number;
  videoSecond: number;
}

const MIN_VIDEO_VIEWPORT_SCALE = 0.4;
const MAX_VIDEO_VIEWPORT_SCALE = 1;

const clamp = (value: number, min: number, max: number) =>
  Math.min(Math.max(value, min), max);

const parseNumberInput = (value: string): number | null => {
  const parsed = Number(value.trim());
  return Number.isFinite(parsed) ? parsed : null;
};

const parseIntegerInput = (value: string): number | null => {
  const parsed = Number.parseInt(value.trim(), 10);
  return Number.isFinite(parsed) ? parsed : null;
};

const sanitizeDigits = (value: string, maxLength: number) =>
  value.replace(/\D/g, "").slice(0, maxLength);

const toDigits = (value: number, width: number) =>
  String(value).padStart(width, "0");

const normalizeTimePart = (
  rawValue: string,
  min: number,
  max: number,
  padLength: number,
) => {
  const parsed = parseIntegerInput(rawValue);
  if (parsed === null) return toDigits(min, padLength);
  return toDigits(clamp(parsed, min, max), padLength);
};

const timestampToDateParts = (timestamp: number) => {
  const date = new Date(timestamp);
  return {
    date: `${date.getFullYear()}-${toDigits(date.getMonth() + 1, 2)}-${toDigits(date.getDate(), 2)}`,
    hour: toDigits(date.getHours(), 2),
    minute: toDigits(date.getMinutes(), 2),
    second: toDigits(date.getSeconds(), 2),
    millisecond: toDigits(date.getMilliseconds(), 3),
  };
};

const buildTimestampFromParts = (
  datePart: string,
  hourPart: string,
  minutePart: string,
  secondPart: string,
  millisecondPart: string,
): number | null => {
  if (!datePart) return null;

  const hour = parseIntegerInput(hourPart);
  const minute = parseIntegerInput(minutePart);
  const second = parseIntegerInput(secondPart);
  const millisecond = parseIntegerInput(millisecondPart);

  if (
    hour === null ||
    minute === null ||
    second === null ||
    millisecond === null ||
    hour < 0 ||
    hour > 23 ||
    minute < 0 ||
    minute > 59 ||
    second < 0 ||
    second > 59 ||
    millisecond < 0 ||
    millisecond > 999
  ) {
    return null;
  }

  const dateTime = new Date(
    `${datePart}T${toDigits(hour, 2)}:${toDigits(minute, 2)}:${toDigits(second, 2)}.${toDigits(millisecond, 3)}`,
  );
  const timestamp = dateTime.getTime();
  return Number.isFinite(timestamp) ? timestamp : null;
};

const formatSeconds = (value: number) => {
  if (!Number.isFinite(value)) return "0.00";
  return value.toFixed(2);
};

const formatSecondsPrecise = (value: number) => {
  if (!Number.isFinite(value)) return "0.000";
  return value.toFixed(3);
};

const formatTelemetryTimestamp = (timestamp: number) =>
  new Date(timestamp).toLocaleString([], {
    hour12: false,
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
  });

const clampRowIndex = (index: number, rowCount: number) => {
  if (rowCount <= 0) return 0;
  return clamp(Math.round(index), 0, rowCount - 1);
};

export const VideoSyncPanel: React.FC<PanelProps> = ({ node }) => {
  const { telemetryRows, packetSelection } = useRobotTelemetry();
  const { videos } = useFilesSnapshot();
  const {
    selectedTime: selectedTelemetryTime,
    activePanelId,
    activePanelPlaying,
  } = useVideoSyncSnapshot();
  const panelId = useMemo(() => node.getId(), [node]);

  const videoRef = useRef<HTMLVideoElement>(null);
  const animationFrameRef = useRef<number | null>(null);
  const lastAnimationUpdateRef = useRef(0);

  const [currentVideoId, setCurrentVideoId] = useState<string | null>(null);
  const [isReplaceMenuOpen, setIsReplaceMenuOpen] = useState(false);

  const [syncMode, setSyncMode] = useState<SyncMode>("beginning");
  const [telemetryTargetMode, setTelemetryTargetMode] =
    useState<TelemetryTargetMode>("packet");
  const [packetNumberInput, setPacketNumberInput] = useState("1");
  const [telemetryDateInput, setTelemetryDateInput] = useState("");
  const [telemetryHourInput, setTelemetryHourInput] = useState("00");
  const [telemetryMinuteInput, setTelemetryMinuteInput] = useState("00");
  const [telemetrySecondInput, setTelemetrySecondInput] = useState("00");
  const [telemetryMillisecondInput, setTelemetryMillisecondInput] =
    useState("000");
  const [videoSecondInput, setVideoSecondInput] = useState("0");
  const [offset, setOffset] = useState<number | null>(null);
  const [syncError, setSyncError] = useState<string | null>(null);
  const [syncAnchor, setSyncAnchor] = useState<SyncAnchor | null>(null);

  const [showPacketMarkers, setShowPacketMarkers] = useState(true);
  const [showSelectedRange, setShowSelectedRange] = useState(true);

  const [videoDuration, setVideoDuration] = useState(0);
  const [videoCurrentTime, setVideoCurrentTime] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [isMuted, setIsMuted] = useState(false);
  const [viewportScale, setViewportScale] = useState(1);
  const resizeSessionRef = useRef<{
    startX: number;
    startY: number;
    startScale: number;
  } | null>(null);

  const currentVideo = useMemo(() => {
    if (videos.length === 0) return null;
    if (currentVideoId === null) return videos[videos.length - 1];
    return (
      videos.find((video) => video.id === currentVideoId) ??
      videos[videos.length - 1]
    );
  }, [currentVideoId, videos]);

  const hasVideo = currentVideo !== null;
  const isSynced = hasVideo && offset !== null;
  const isUploadState = !hasVideo;
  const isTimestampState = hasVideo && !isSynced;
  const isFullySyncedState = isSynced;
  const isMainPanel = activePanelId === panelId;

  const stopPlaybackLoop = useCallback(() => {
    if (animationFrameRef.current !== null) {
      window.cancelAnimationFrame(animationFrameRef.current);
      animationFrameRef.current = null;
    }
  }, []);

  // Keep a ref to the current scale to avoid re-creating the resize handler
  // on every frame during a drag (since setViewportScale triggers re-render).
  const viewportScaleRef = useRef(viewportScale);
  viewportScaleRef.current = viewportScale;

  const beginViewportResize = useCallback(
    (event: React.PointerEvent<HTMLElement>) => {
      event.preventDefault();

      resizeSessionRef.current = {
        startX: event.clientX,
        startY: event.clientY,
        startScale: viewportScaleRef.current,
      };

      const onPointerMove = (moveEvent: PointerEvent) => {
        const session = resizeSessionRef.current;
        if (!session) return;

        const deltaX = moveEvent.clientX - session.startX;
        const deltaY = moveEvent.clientY - session.startY;

        // Dragging left/up shrinks. Dragging right/down expands (capped at 100%).
        const delta = (deltaX + deltaY) / 2;
        const nextScale = clamp(
          session.startScale + delta / 700,
          MIN_VIDEO_VIEWPORT_SCALE,
          MAX_VIDEO_VIEWPORT_SCALE,
        );
        setViewportScale(nextScale);
      };

      const onPointerUp = () => {
        resizeSessionRef.current = null;
        window.removeEventListener("pointermove", onPointerMove);
        window.removeEventListener("pointerup", onPointerUp);
        window.removeEventListener("pointercancel", onPointerUp);
      };

      window.addEventListener("pointermove", onPointerMove);
      window.addEventListener("pointerup", onPointerUp);
      window.addEventListener("pointercancel", onPointerUp);
    },
    [],
  );

  const publishVideoTelemetryTime = useCallback(
    (videoTime: number) => {
      if (!isSynced || offset === null || !isMainPanel) return;
      const telemetryTime = videoTime * 1000 + offset;
      videoSyncManager.setSelectedTime(telemetryTime);
    },
    [isMainPanel, isSynced, offset],
  );

  const seekVideo = useCallback(
    (nextTime: number) => {
      const duration = Math.max(videoDuration, 0);
      const clampedTime = duration > 0 ? clamp(nextTime, 0, duration) : 0;
      const videoElement = videoRef.current;

      if (
        videoElement &&
        Math.abs(videoElement.currentTime - clampedTime) > 0.01
      ) {
        videoElement.currentTime = clampedTime;
      }

      setVideoCurrentTime((previousTime) =>
        Math.abs(previousTime - clampedTime) > 0.01
          ? clampedTime
          : previousTime,
      );
      publishVideoTelemetryTime(clampedTime);
    },
    [publishVideoTelemetryTime, videoDuration],
  );

  const startPlaybackLoop = useCallback(() => {
    stopPlaybackLoop();
    lastAnimationUpdateRef.current = 0;
    const tick = (now: number) => {
      const videoElement = videoRef.current;
      if (!videoElement) {
        stopPlaybackLoop();
        return;
      }

      if (now - lastAnimationUpdateRef.current >= 33) {
        lastAnimationUpdateRef.current = now;
        const nextTime = videoElement.currentTime;
        setVideoCurrentTime((previousTime) =>
          Math.abs(previousTime - nextTime) > 0.015 ? nextTime : previousTime,
        );
        publishVideoTelemetryTime(nextTime);
      }

      if (!videoElement.paused && !videoElement.ended) {
        animationFrameRef.current = window.requestAnimationFrame(tick);
      } else {
        setIsPlaying(false);
        stopPlaybackLoop();
      }
    };

    animationFrameRef.current = window.requestAnimationFrame(tick);
  }, [publishVideoTelemetryTime, stopPlaybackLoop]);

  useEffect(
    () => () => {
      stopPlaybackLoop();
    },
    [stopPlaybackLoop],
  );

  useEffect(() => {
    if (!isSynced || offset === null || selectedTelemetryTime === null) return;
    if (videoDuration <= 0) return;

    const nextVideoTime = clamp(
      (selectedTelemetryTime - offset) / 1000,
      0,
      videoDuration,
    );
    const videoElement = videoRef.current;
    if (!videoElement) return;
    const drift = nextVideoTime - videoElement.currentTime;
    const absDrift = Math.abs(drift);

    // Secondary panels follow by position only; they do not play media/audio.
    if (!isMainPanel && activePanelPlaying) {
      if (!videoElement.paused) {
        videoElement.pause();
      }
      if (absDrift > 0.08) {
        videoElement.currentTime = nextVideoTime;
      }
      return;
    }

    if (!isMainPanel && !videoElement.paused) {
      videoElement.pause();
    }

    if (isPlaying) return;
    if (absDrift <= 0.05) return;
    videoElement.currentTime = nextVideoTime;
  }, [
    activePanelPlaying,
    isMainPanel,
    isPlaying,
    isSynced,
    offset,
    selectedTelemetryTime,
    videoDuration,
  ]);

  const packetMarkerTimes = useMemo(() => {
    if (!isSynced || offset === null || videoDuration <= 0)
      return [] as number[];

    const markers: number[] = [];
    telemetryRows.forEach((row) => {
      const mappedVideoTime = (row.timestamp - offset) / 1000;
      if (mappedVideoTime < 0 || mappedVideoTime > videoDuration) return;
      markers.push(mappedVideoTime);
    });
    return markers;
  }, [isSynced, offset, telemetryRows, videoDuration]);

  const selectedRange = useMemo(() => {
    if (!isSynced || offset === null || videoDuration <= 0) return null;
    if (telemetryRows.length === 0) return null;

    const startIndex = clampRowIndex(
      packetSelection.startIndex,
      telemetryRows.length,
    );
    const endIndex = clampRowIndex(
      packetSelection.endIndex,
      telemetryRows.length,
    );
    const lowIndex = Math.min(startIndex, endIndex);
    const highIndex = Math.max(startIndex, endIndex);
    const startRow = telemetryRows[lowIndex];
    const endRow = telemetryRows[highIndex];
    if (!startRow || !endRow) return null;

    const rawStart = (startRow.timestamp - offset) / 1000;
    const rawEnd = (endRow.timestamp - offset) / 1000;
    const clampedStart = clamp(Math.min(rawStart, rawEnd), 0, videoDuration);
    const clampedEnd = clamp(Math.max(rawStart, rawEnd), 0, videoDuration);

    if (clampedEnd <= clampedStart) return null;
    if (clampedEnd <= 0 || clampedStart >= videoDuration) return null;

    return { start: clampedStart, end: clampedEnd };
  }, [
    isSynced,
    offset,
    packetSelection.endIndex,
    packetSelection.startIndex,
    telemetryRows,
    videoDuration,
  ]);

  const telemetryBounds = useMemo(() => {
    if (telemetryRows.length === 0) return null;

    let minTimestamp = telemetryRows[0].timestamp;
    let maxTimestamp = telemetryRows[0].timestamp;
    telemetryRows.forEach((row) => {
      if (row.timestamp < minTimestamp) minTimestamp = row.timestamp;
      if (row.timestamp > maxTimestamp) maxTimestamp = row.timestamp;
    });

    return { minTimestamp, maxTimestamp };
  }, [telemetryRows]);

  const packetCount = telemetryRows.length;

  const switchToVideo = (videoId: string, forceResync = false) => {
    setCurrentVideoId(videoId);
    setIsReplaceMenuOpen(false);

    // Check if we have persisted sync data for this video, unless forcing a resync
    const videoRecord = filesManager.getVideoById(videoId);
    if (!forceResync && videoRecord?.syncData) {
      setOffset(videoRecord.syncData.offset);
      setSyncAnchor(videoRecord.syncData.anchor);
      setSyncMode(videoRecord.syncData.anchor.mode);
      setVideoSecondInput(String(videoRecord.syncData.anchor.videoSecond));
      setSyncError(null);
      // We keep existing playback state stops
      setVideoCurrentTime(0);
      setVideoDuration(videoRecord.durationSeconds || 0); // Optimistically use cached duration
      setIsPlaying(false);
      stopPlaybackLoop();
      return; // Skip default reset logic if we loaded sync data
    }

    setSyncMode("beginning");
    setOffset(null);
    setSyncAnchor(null);
    setSyncError(null);
    setVideoSecondInput("0");
    setVideoCurrentTime(0);
    setVideoDuration(0);
    setIsPlaying(false);
    stopPlaybackLoop();

    const defaultTimestamp =
      selectedTelemetryTime ??
      (telemetryRows.length > 0
        ? telemetryRows[telemetryRows.length - 1].timestamp
        : 0);
    const dateParts = timestampToDateParts(defaultTimestamp);
    setTelemetryDateInput(dateParts.date);
    setTelemetryHourInput(dateParts.hour);
    setTelemetryMinuteInput(dateParts.minute);
    setTelemetrySecondInput(dateParts.second);
    setTelemetryMillisecondInput(dateParts.millisecond);

    const nearestPacketNumber =
      telemetryRows.length === 0
        ? 1
        : Math.max(
          1,
          telemetryRows.reduce((closestIndex, row, index) => {
            const closestDistance = Math.abs(
              telemetryRows[closestIndex].timestamp - defaultTimestamp,
            );
            const currentDistance = Math.abs(
              row.timestamp - defaultTimestamp,
            );
            return currentDistance < closestDistance ? index : closestIndex;
          }, 0) + 1,
        );
    setPacketNumberInput(String(nearestPacketNumber));
  };

  const applySync = () => {
    const telemetryTimestamp =
      telemetryTargetMode === "packet"
        ? (() => {
          const packetNumber = parseIntegerInput(packetNumberInput);
          if (packetNumber === null) return null;
          if (telemetryRows.length === 0) return null;
          const index = clamp(packetNumber - 1, 0, telemetryRows.length - 1);
          return telemetryRows[index]?.timestamp ?? null;
        })()
        : buildTimestampFromParts(
          telemetryDateInput,
          telemetryHourInput,
          telemetryMinuteInput,
          telemetrySecondInput,
          telemetryMillisecondInput,
        );

    if (telemetryTimestamp === null) {
      setSyncError(
        telemetryTargetMode === "packet"
          ? "Choose a valid packet number and ensure telemetry rows exist."
          : "Provide a valid full date/time with millisecond precision.",
      );
      return;
    }

    const parsedVideoSecond =
      syncMode === "beginning" ? 0 : parseNumberInput(videoSecondInput);
    if (parsedVideoSecond === null) {
      setSyncError("Video second must be a valid number.");
      return;
    }
    if (parsedVideoSecond < 0) {
      setSyncError("Video second must be zero or greater.");
      return;
    }

    if (telemetryTargetMode === "datetime") {
      const hour = parseIntegerInput(telemetryHourInput);
      const minute = parseIntegerInput(telemetryMinuteInput);
      const second = parseIntegerInput(telemetrySecondInput);
      const millisecond = parseIntegerInput(telemetryMillisecondInput);
      const invalidTimeFields =
        hour === null ||
        minute === null ||
        second === null ||
        millisecond === null ||
        hour < 0 ||
        hour > 23 ||
        minute < 0 ||
        minute > 59 ||
        second < 0 ||
        second > 59 ||
        millisecond < 0 ||
        millisecond > 999;
      if (invalidTimeFields) {
        setSyncError(
          "Time fields must be valid: hr 00-23, min/sec 00-59, ms 000-999.",
        );
        return;
      }
    }

    const normalizedVideoSecond =
      videoDuration > 0
        ? clamp(parsedVideoSecond, 0, videoDuration)
        : parsedVideoSecond;
    const nextOffset = telemetryTimestamp - normalizedVideoSecond * 1000;

    setOffset(nextOffset);
    const newAnchor = {
      mode: syncMode,
      telemetryTimestamp,
      videoSecond: normalizedVideoSecond,
    };
    setSyncAnchor(newAnchor);
    setVideoSecondInput(String(normalizedVideoSecond));
    setSyncError(null);

    // Persist sync settings to the file record
    if (currentVideoId) {
      filesManager.updateVideoSyncData(currentVideoId, nextOffset, newAnchor);
    }
  };

  const seekToNextPacket = () => {
    if (!isSynced || offset === null || telemetryRows.length === 0) return;

    const currentTelemetryTime = videoCurrentTime * 1000 + offset;
    const nextRow = telemetryRows.find(
      (row) => row.timestamp > currentTelemetryTime + 0.5,
    );
    if (!nextRow) {
      seekVideo(videoDuration);
      return;
    }

    const nextVideoTime = (nextRow.timestamp - offset) / 1000;
    seekVideo(nextVideoTime);
  };

  const seekToPreviousPacket = () => {
    if (!isSynced || offset === null || telemetryRows.length === 0) return;

    const currentTelemetryTime = videoCurrentTime * 1000 + offset;
    let previousRow = telemetryRows[0];
    for (let index = telemetryRows.length - 1; index >= 0; index -= 1) {
      const row = telemetryRows[index];
      if (row.timestamp < currentTelemetryTime - 0.5) {
        previousRow = row;
        break;
      }
    }

    const previousVideoTime = (previousRow.timestamp - offset) / 1000;
    seekVideo(previousVideoTime);
  };

  const syncControls = (
    <div className="grid gap-3">
      <div>
        <label className="ui-label" htmlFor="video-sync-mode">
          Sync Mode
        </label>
        <select
          id="video-sync-mode"
          className="ui-input"
          value={syncMode}
          onChange={(event) => setSyncMode(event.target.value as SyncMode)}
        >
          <option value="beginning">Timestamp beginning of video</option>
          <option value="segment">Timestamp specific segment</option>
        </select>
      </div>

      {syncMode === "segment" ? (
        <div className="flex flex-wrap items-end gap-3">
          <div className="flex-1 min-w-0">
            <label className="ui-label" htmlFor="video-sync-second">
              Video second (since beginning)
            </label>
            <input
              id="video-sync-second"
              className="ui-input"
              type="text"
              inputMode="decimal"
              value={videoSecondInput}
              onChange={(event) => setVideoSecondInput(event.target.value)}
            />
          </div>
          <button
            type="button"
            className="ui-btn ui-btn-outline h-10"
            onClick={() => {
              const videoElement = videoRef.current;
              const currentSecond =
                videoElement?.currentTime ?? videoCurrentTime;
              setVideoSecondInput(String(currentSecond));
            }}
          >
            Use current video position
          </button>
        </div>
      ) : null}

      <div>
        <label className="ui-label" htmlFor="video-sync-telemetry-target-mode">
          Telemetry target
        </label>
        <select
          id="video-sync-telemetry-target-mode"
          className="ui-input"
          value={telemetryTargetMode}
          onChange={(event) =>
            setTelemetryTargetMode(event.target.value as TelemetryTargetMode)
          }
        >
          <option value="packet">Telemetry packet</option>
          <option value="datetime">Specific date/time</option>
        </select>
      </div>

      <div>
        <label className="ui-label" htmlFor="video-sync-telemetry-ts">
          {telemetryTargetMode === "packet"
            ? "Telemetry packet number"
            : "Telemetry date/time"}
        </label>
        {telemetryTargetMode === "packet" ? (
          <input
            id="video-sync-telemetry-ts"
            className="ui-input"
            type="text"
            inputMode="numeric"
            value={packetNumberInput}
            onChange={(event) =>
              setPacketNumberInput(event.target.value.replace(/\D/g, ""))
            }
          />
        ) : (
          <div className="flex flex-wrap items-center gap-2">
            <div className="min-w-[12rem] flex-1">
              <input
                id="video-sync-telemetry-ts"
                className="ui-input h-9"
                type="date"
                title="Date"
                aria-label="Telemetry date"
                value={telemetryDateInput}
                onChange={(event) => setTelemetryDateInput(event.target.value)}
              />
            </div>

            <div className="relative w-[4.5rem]">
              <span
                className="pointer-events-none absolute right-2 top-1/2 -translate-y-1/2 text-xs"
                style={{ color: "hsl(var(--secondary-foreground) / 0.65)" }}
              >
                hr
              </span>
              <input
                className="ui-input h-9 pr-7"
                type="text"
                inputMode="numeric"
                placeholder="00"
                title="Hour (00-23)"
                aria-label="Telemetry hour"
                value={telemetryHourInput}
                onChange={(event) =>
                  setTelemetryHourInput(sanitizeDigits(event.target.value, 2))
                }
                onBlur={() =>
                  setTelemetryHourInput(
                    normalizeTimePart(telemetryHourInput, 0, 23, 2),
                  )
                }
              />
            </div>

            <div className="relative w-[4.5rem]">
              <span
                className="pointer-events-none absolute right-2 top-1/2 -translate-y-1/2 text-xs"
                style={{ color: "hsl(var(--secondary-foreground) / 0.65)" }}
              >
                min
              </span>
              <input
                className="ui-input h-9 pr-8"
                type="text"
                inputMode="numeric"
                placeholder="00"
                title="Minute (00-59)"
                aria-label="Telemetry minute"
                value={telemetryMinuteInput}
                onChange={(event) =>
                  setTelemetryMinuteInput(sanitizeDigits(event.target.value, 2))
                }
                onBlur={() =>
                  setTelemetryMinuteInput(
                    normalizeTimePart(telemetryMinuteInput, 0, 59, 2),
                  )
                }
              />
            </div>

            <div className="relative w-[4.5rem]">
              <span
                className="pointer-events-none absolute right-2 top-1/2 -translate-y-1/2 text-xs"
                style={{ color: "hsl(var(--secondary-foreground) / 0.65)" }}
              >
                sec
              </span>
              <input
                className="ui-input h-9 pr-8"
                type="text"
                inputMode="numeric"
                placeholder="00"
                title="Second (00-59)"
                aria-label="Telemetry second"
                value={telemetrySecondInput}
                onChange={(event) =>
                  setTelemetrySecondInput(sanitizeDigits(event.target.value, 2))
                }
                onBlur={() =>
                  setTelemetrySecondInput(
                    normalizeTimePart(telemetrySecondInput, 0, 59, 2),
                  )
                }
              />
            </div>

            <div className="relative w-[5.25rem]">
              <span
                className="pointer-events-none absolute right-2 top-1/2 -translate-y-1/2 text-xs"
                style={{ color: "hsl(var(--secondary-foreground) / 0.65)" }}
              >
                ms
              </span>
              <input
                className="ui-input h-9 pr-8"
                type="text"
                inputMode="numeric"
                placeholder="000"
                title="Millisecond (000-999)"
                aria-label="Telemetry millisecond"
                value={telemetryMillisecondInput}
                onChange={(event) =>
                  setTelemetryMillisecondInput(
                    sanitizeDigits(event.target.value, 3),
                  )
                }
                onBlur={() =>
                  setTelemetryMillisecondInput(
                    normalizeTimePart(telemetryMillisecondInput, 0, 999, 3),
                  )
                }
              />
            </div>
          </div>
        )}
        <p className="mt-1 text-xs text-muted-foreground">
          {telemetryBounds
            ? `Telemetry span: ${formatTelemetryTimestamp(telemetryBounds.minTimestamp)} - ${formatTelemetryTimestamp(telemetryBounds.maxTimestamp)} | Packets: ${packetCount}`
            : "No telemetry rows loaded yet. Packet target requires telemetry; date/time target can still be set manually."}
        </p>
        {telemetryTargetMode === "datetime" ? (
          <p className="mt-1 text-xs text-muted-foreground">
            Use Date + hr/min/sec/ms fields.
          </p>
        ) : null}
      </div>

      {syncError ? (
        <p className="text-xs text-[hsl(var(--error))]" aria-live="polite">
          {syncError}
        </p>
      ) : null}

      <div className="flex flex-wrap items-center gap-2">
        <button
          type="button"
          className="ui-btn ui-btn-primary"
          onClick={applySync}
        >
          {isFullySyncedState ? "Re-sync video" : "Apply sync"}
        </button>
        {syncAnchor ? (
          <span className="text-xs text-muted-foreground">
            Applied: video {formatSeconds(syncAnchor.videoSecond)}s {"<->"}{" "}
            telemetry {Math.round(syncAnchor.telemetryTimestamp)}ms
          </span>
        ) : null}
      </div>
    </div>
  );

  if (isUploadState) {
    return (
      <div className="panel-content">
        <div className="panel-shell">
          <section className="ui-card">
            <div className="flex min-h-[220px] flex-col items-center justify-center rounded-md border border-border p-6 text-center">
              <i className="fa-solid fa-film mb-4 text-3xl text-muted-foreground" />
              <h2 className="text-base font-semibold">No video selected</h2>
              <p className="mt-2 text-sm text-muted-foreground">
                Add videos from the Files panel, then select one here.
              </p>
              <button
                type="button"
                className="ui-btn ui-btn-outline mt-4"
                onClick={() => setIsReplaceMenuOpen((open) => !open)}
                disabled={videos.length === 0}
              >
                {videos.length === 0 ? "No videos in Files" : "Select video"}
              </button>
              {isReplaceMenuOpen && videos.length > 0 ? (
                <div className="ui-menu mt-3 max-h-48 w-full overflow-y-auto p-1 text-left">
                  {videos.map((video) => (
                    <button
                      key={video.id}
                      type="button"
                      className="ui-menu-item"
                      onClick={() => switchToVideo(video.id)}
                    >
                      <span className="truncate">{video.name}</span>
                    </button>
                  ))}
                </div>
              ) : null}
            </div>
          </section>
        </div>
      </div>
    );
  }

  return (
    <div className="panel-content">
      <div
        className="panel-shell"
        onPointerDownCapture={() => {
          if (isSynced) {
            videoSyncManager.setActivePanel(panelId);
          }
        }}
      >
        <section className="ui-card">
          <div className="grid gap-3">
            <div
              className="mx-auto w-full"
              style={{ width: `${viewportScale * 100}%` }}
            >
              <div className="relative overflow-hidden rounded-md border border-border bg-black/40">
                <video
                  ref={videoRef}
                  src={currentVideo?.objectUrl}
                  className="h-auto w-full"
                  controls={false}
                  muted={isMainPanel ? isMuted : true}
                  preload="metadata"
                  onLoadedMetadata={() => {
                    const duration = Number(videoRef.current?.duration ?? 0);
                    setVideoDuration(Number.isFinite(duration) ? duration : 0);
                    if (currentVideo && Number.isFinite(duration)) {
                      filesManager.updateVideoDuration(
                        currentVideo.id,
                        duration,
                      );
                    }
                  }}
                  onPlay={() => {
                    setIsPlaying(true);
                    if (isSynced) {
                      videoSyncManager.setActivePanel(panelId);
                      videoSyncManager.setActivePanelPlaying(panelId, true);
                    } else {
                      videoSyncManager.setActivePanelPlaying(panelId, false);
                    }
                    startPlaybackLoop();
                  }}
                  onPause={() => {
                    setIsPlaying(false);
                    videoSyncManager.setActivePanelPlaying(panelId, false);
                    stopPlaybackLoop();
                    const current = videoRef.current?.currentTime ?? 0;
                    setVideoCurrentTime(current);
                    publishVideoTelemetryTime(current);
                  }}
                  onEnded={() => {
                    setIsPlaying(false);
                    videoSyncManager.setActivePanelPlaying(panelId, false);
                    stopPlaybackLoop();
                    const current = videoRef.current?.currentTime ?? 0;
                    setVideoCurrentTime(current);
                    publishVideoTelemetryTime(current);
                  }}
                  onTimeUpdate={() => {
                    const videoElement = videoRef.current;
                    if (!videoElement) return;
                    if (!videoElement.paused && !videoElement.ended) return;
                    const current = videoElement.currentTime;
                    setVideoCurrentTime(current);
                    publishVideoTelemetryTime(current);
                  }}
                />

                {/* Resize handles: right edge, bottom edge, bottom-right corner */}
                <button
                  type="button"
                  className="absolute right-0 top-0 h-full w-5 translate-x-1/2 cursor-ew-resize bg-transparent"
                  aria-label="Resize video viewport"
                  title="Drag to resize video viewport"
                  onPointerDown={beginViewportResize}
                />
                <button
                  type="button"
                  className="absolute bottom-0 left-0 h-5 w-full translate-y-1/2 cursor-ns-resize bg-transparent"
                  aria-label="Resize video viewport"
                  title="Drag to resize video viewport"
                  onPointerDown={beginViewportResize}
                />
                <button
                  type="button"
                  className="absolute bottom-0 right-0 h-6 w-6 translate-x-1/2 translate-y-1/2 cursor-nwse-resize bg-transparent"
                  aria-label="Resize video viewport"
                  title="Drag to resize video viewport"
                  onPointerDown={beginViewportResize}
                />
              </div>
            </div>

            <div className="grid grid-cols-[1fr_auto_1fr] items-center gap-2">
              <div
                className="ui-btn ui-btn-outline h-9 px-3 justify-self-start cursor-default select-none text-xs font-medium pointer-events-none"
                role="status"
                aria-live="off"
              >
                {formatSecondsPrecise(videoCurrentTime)}s/
                {formatSecondsPrecise(videoDuration)}s
              </div>
              <div className="flex items-center justify-center gap-1">
                <button
                  type="button"
                  className="ui-btn ui-btn-outline h-9 w-9 p-0"
                  onClick={() => seekVideo(0)}
                  disabled={videoDuration <= 0}
                  title="Go to start"
                  aria-label="Go to start"
                >
                  <ArrowLeftToLine size={16} />
                </button>
                <button
                  type="button"
                  className="ui-btn ui-btn-outline h-9 w-9 p-0"
                  onClick={() => seekVideo(videoCurrentTime - 5)}
                  disabled={videoDuration <= 0}
                  title="Back 5 seconds"
                  aria-label="Back 5 seconds"
                >
                  <Rewind size={16} />
                </button>
                <button
                  type="button"
                  className="ui-btn ui-btn-outline h-9 w-9 p-0"
                  onClick={seekToPreviousPacket}
                  disabled={
                    !isSynced ||
                    telemetryRows.length === 0 ||
                    videoDuration <= 0
                  }
                  title="Previous packet"
                  aria-label="Previous packet"
                >
                  <SkipBack size={16} />
                </button>
                <button
                  type="button"
                  className="ui-btn ui-btn-outline h-9 w-9 p-0"
                  onClick={() => seekVideo(videoCurrentTime - 1 / 30)}
                  disabled={videoDuration <= 0}
                  title="Previous frame"
                  aria-label="Previous frame"
                >
                  <StepBack size={16} />
                </button>
                <button
                  type="button"
                  className="ui-btn ui-btn-secondary h-10 w-10 p-0"
                  onClick={() => {
                    const videoElement = videoRef.current;
                    if (!videoElement) return;
                    if (isSynced) {
                      videoSyncManager.setActivePanel(panelId);
                    }
                    if (videoElement.paused) {
                      void videoElement.play();
                    } else {
                      videoElement.pause();
                    }
                  }}
                  title={isPlaying ? "Pause" : "Play"}
                  aria-label={isPlaying ? "Pause" : "Play"}
                >
                  {isPlaying ? <Pause size={18} /> : <Play size={18} />}
                </button>
                <button
                  type="button"
                  className="ui-btn ui-btn-outline h-9 w-9 p-0"
                  onClick={() => seekVideo(videoCurrentTime + 1 / 30)}
                  disabled={videoDuration <= 0}
                  title="Next frame"
                  aria-label="Next frame"
                >
                  <StepForward size={16} />
                </button>
                <button
                  type="button"
                  className="ui-btn ui-btn-outline h-9 w-9 p-0"
                  onClick={seekToNextPacket}
                  disabled={
                    !isSynced ||
                    telemetryRows.length === 0 ||
                    videoDuration <= 0
                  }
                  title="Next packet"
                  aria-label="Next packet"
                >
                  <SkipForward size={16} />
                </button>
                <button
                  type="button"
                  className="ui-btn ui-btn-outline h-9 w-9 p-0"
                  onClick={() => seekVideo(videoCurrentTime + 5)}
                  disabled={videoDuration <= 0}
                  title="Forward 5 seconds"
                  aria-label="Forward 5 seconds"
                >
                  <FastForward size={16} />
                </button>
                <button
                  type="button"
                  className="ui-btn ui-btn-outline h-9 w-9 p-0"
                  onClick={() => seekVideo(videoDuration)}
                  disabled={videoDuration <= 0}
                  title="Jump to end"
                  aria-label="Jump to end"
                >
                  <ArrowRightToLine size={16} />
                </button>
              </div>
              <div className="justify-self-end">
                <div className="relative flex items-center gap-1">
                  <button
                    type="button"
                    className="ui-btn ui-btn-outline h-9 w-9 p-0"
                    onClick={() => setIsMuted((muted) => !muted)}
                    title={isMuted ? "Unmute" : "Mute"}
                    aria-label={isMuted ? "Unmute" : "Mute"}
                  >
                    {isMuted ? <VolumeX size={16} /> : <Volume2 size={16} />}
                  </button>
                  <button
                    type="button"
                    className="ui-btn ui-btn-outline h-9 w-9 p-0"
                    onClick={() => setIsReplaceMenuOpen((open) => !open)}
                    title="Replace video"
                    aria-label="Replace video"
                  >
                    <FolderOpen size={16} />
                  </button>
                  {isReplaceMenuOpen ? (
                    <div className="ui-menu absolute right-0 top-full z-30 mt-2 max-h-60 w-72 overflow-y-auto p-1">
                      {videos.length === 0 ? (
                        <div className="px-3 py-2 text-xs text-muted-foreground">
                          No videos in Files panel.
                        </div>
                      ) : (
                        videos.map((video) => (
                          <button
                            key={video.id}
                            type="button"
                            className="ui-menu-item"
                            onClick={() => switchToVideo(video.id)}
                          >
                            <span className="truncate">{video.name}</span>
                          </button>
                        ))
                      )}
                    </div>
                  ) : null}
                </div>
              </div>
            </div>

            <SmartVideoSlider
              duration={videoDuration}
              currentTime={videoCurrentTime}
              onSeek={seekVideo}
              disabled={videoDuration <= 0}
              showPacketMarkers={isSynced && showPacketMarkers}
              packetMarkerTimes={packetMarkerTimes}
              showSelectedRange={isSynced && showSelectedRange}
              selectedRange={selectedRange}
            />

            {isTimestampState || isFullySyncedState ? (
              <div
                className={`rounded-md border border-border bg-card p-3 ${isFullySyncedState ? "mt-4" : ""
                  }`}
              >
                <h2 className="mb-2 text-sm font-semibold">
                  {isFullySyncedState ? "Adjust Sync" : "Timestamp this video"}
                </h2>
                {syncControls}
              </div>
            ) : null}
          </div>
        </section>

        {isSynced ? (
          <section className="ui-card">
            <div className="grid gap-5">
              <div>
                <h2 className="ui-card-title">Packet Display Controls</h2>
                <div className="grid gap-2 text-sm">
                  <label className="inline-flex items-center gap-2 text-foreground">
                    <input
                      type="checkbox"
                      checked={showPacketMarkers}
                      onChange={(event) =>
                        setShowPacketMarkers(event.target.checked)
                      }
                    />
                    Display packets
                  </label>
                  <label className="inline-flex items-center gap-2 text-foreground">
                    <input
                      type="checkbox"
                      checked={showSelectedRange}
                      onChange={(event) =>
                        setShowSelectedRange(event.target.checked)
                      }
                    />
                    Display range of selected packets
                  </label>
                </div>
              </div>
            </div>
          </section>
        ) : null}
      </div>
    </div>
  );
};

export type RobotConnectionStatus = "disconnected" | "connecting" | "connected";
export type TelemetryValue = string | number | boolean;

export interface TelemetryDatum {
  name: string;
  value: TelemetryValue;
}

export interface TelemetryRow {
  id: number;
  timestamp: number;
  values: Record<string, TelemetryValue>;
}

export interface PacketSelection {
  startIndex: number;
  endIndex: number;
  endFollowsLatest: boolean;
}

export interface RobotTelemetrySnapshot {
  connectionStatus: RobotConnectionStatus;
  ipAddress: string;
  connectionMessage: string | null;
  telemetryColumns: string[];
  telemetryRows: TelemetryRow[];
  packetSelection: PacketSelection;
  streamPaused: boolean;
}

const MAX_TELEMETRY_ROWS = 1000;

interface ImportTelemetryRow {
  id?: number;
  timestamp: number;
  values: Record<string, TelemetryValue>;
}

class RobotTelemetryManager {
  private connectionStatus: RobotConnectionStatus = "disconnected";

  private ipAddress = "192.168.43.1:12345";

  private connectionMessage: string | null = null;

  private telemetryColumns: string[] = [];

  private telemetryRows: TelemetryRow[] = [];

  private nextRowId = 1;

  private packetSelection: PacketSelection = {
    startIndex: 0,
    endIndex: 0,
    endFollowsLatest: true,
  };

  private listeners = new Set<() => void>();

  private connectTimer: number | null = null;

  private pollingAbortController: AbortController | null = null;

  private pollingTimer: number | null = null;

  private mockStreamTimer: number | null = null;

  private streamPaused = false;

  private isDemoMode = false;

  private snapshot: RobotTelemetrySnapshot = {
    connectionStatus: this.connectionStatus,
    ipAddress: this.ipAddress,
    connectionMessage: this.connectionMessage,
    telemetryColumns: this.telemetryColumns,
    telemetryRows: this.telemetryRows,
    packetSelection: this.packetSelection,
    streamPaused: this.streamPaused,
  };

  constructor() {
    this.rebuildSnapshot();
  }

  subscribe = (listener: () => void) => {
    this.listeners.add(listener);
    return () => {
      this.listeners.delete(listener);
    };
  };

  getSnapshot = () => this.snapshot;

  setIpAddress = (ipAddress: string) => {
    const sanitized = ipAddress.replace(/\s+/g, "");
    if (sanitized === this.ipAddress) return;
    this.ipAddress = sanitized;
    this.emit();
  };

  setPacketSelectionStartByIndex = (startIndex: number) => {
    const maxIndex = Math.max(0, this.telemetryRows.length - 1);
    const clampedStart = Math.min(Math.max(Math.round(startIndex), 0), maxIndex);
    const nextEnd = Math.max(this.packetSelection.endIndex, clampedStart);

    this.packetSelection = {
      ...this.packetSelection,
      startIndex: clampedStart,
      endIndex: nextEnd,
    };
    this.emit();
  };

  setPacketSelectionEndByIndex = (endIndex: number) => {
    const maxIndex = Math.max(0, this.telemetryRows.length - 1);
    const clampedEnd = Math.min(Math.max(Math.round(endIndex), 0), maxIndex);
    const nextStart = Math.min(this.packetSelection.startIndex, clampedEnd);

    this.packetSelection = {
      startIndex: nextStart,
      endIndex: clampedEnd,
      endFollowsLatest: false,
    };
    this.emit();
  };

  setPacketSelectionStartByPacketNumber = (packetNumber: number) => {
    this.setPacketSelectionStartByIndex(packetNumber - 1);
  };

  setPacketSelectionEndByPacketNumber = (packetNumber: number) => {
    this.setPacketSelectionEndByIndex(packetNumber - 1);
  };

  setPacketSelectionStartByTimestamp = (timestamp: number) => {
    const nearestIndex = this.findNearestRowIndexForTimestamp(timestamp);
    if (nearestIndex === null) return;
    this.setPacketSelectionStartByIndex(nearestIndex);
  };

  setPacketSelectionEndByTimestamp = (timestamp: number) => {
    const nearestIndex = this.findNearestRowIndexForTimestamp(timestamp);
    if (nearestIndex === null) return;
    this.setPacketSelectionEndByIndex(nearestIndex);
  };

  setPacketSelectionFollowLatest = (endFollowsLatest: boolean) => {
    const lastIndex = Math.max(0, this.telemetryRows.length - 1);

    if (endFollowsLatest) {
      this.packetSelection = {
        startIndex: Math.min(this.packetSelection.startIndex, lastIndex),
        endIndex: lastIndex,
        endFollowsLatest: true,
      };
    } else {
      this.packetSelection = {
        ...this.packetSelection,
        endFollowsLatest: false,
      };
    }

    this.emit();
  };

  setStreamPaused = (paused: boolean) => {
    if (this.streamPaused === paused) return;
    this.streamPaused = paused;
    if (this.streamPaused) {
      // Polling loop will see this flag and skip fetches, effectively pausing
      this.stopMockStream();
    } else if (this.connectionStatus === "connected") {
      if (this.isDemoMode) {
        this.startMockStream();
      } else {
        // Resume polling immediately instead of waiting for next interval
        const connectTarget = this.ipAddress.trim();
        this.startPolling(connectTarget);
      }
    }
    this.emit();
  };

  toggleStreamPaused = () => {
    this.setStreamPaused(!this.streamPaused);
  };

  connect = () => {
    if (this.connectionStatus !== "disconnected") return;
    const connectTarget = this.ipAddress.trim();
    if (!connectTarget) {
      this.connectionMessage = "Enter a robot address or type demo.";
      this.emit();
      return;
    }

    this.connectionStatus = "connecting";
    this.connectionMessage = null;
    this.emit();

    this.clearConnectTimer();
    if (connectTarget.toLowerCase() === "demo") {
      this.isDemoMode = true;
      this.connectTimer = window.setTimeout(() => {
        this.connectionStatus = "connected";
        this.connectionMessage = "Connected in demo mode.";
        if (!this.streamPaused) {
          this.startMockStream();
        }
        this.emit();
      }, 700);
      return;
    }

    this.isDemoMode = false;
    this.startPolling(connectTarget);
  };

  disconnect = () => {
    this.clearConnectTimer();
    this.stopMockStream();
    this.stopPolling();
    this.isDemoMode = false;
    if (this.connectionStatus === "disconnected") return;
    this.connectionStatus = "disconnected";
    this.connectionMessage = null;
    this.streamPaused = false;
    this.emit();
  };

  toggleConnection = () => {
    if (this.connectionStatus === "disconnected") {
      this.connect();
      return;
    }
    this.disconnect();
  };

  generateRandomTelemetrySample = () => {
    const now = Date.now();
    this.addTelemetrySample(this.createRandomTelemetryDatums(now), now);
  };

  addTelemetrySample = (data: TelemetryDatum[], timestamp = Date.now()) => {
    const values: Record<string, TelemetryValue> = {};

    data.forEach((datum) => {
      const name = datum.name.trim();
      if (!name) return;
      if (!this.telemetryColumns.includes(name)) {
        this.telemetryColumns = [...this.telemetryColumns, name];
      }
      values[name] = datum.value;
    });

    if (Object.keys(values).length === 0) return;

    const row: TelemetryRow = {
      id: this.nextRowId++,
      timestamp,
      values,
    };

    const nextRows = [...this.telemetryRows, row];
    this.telemetryRows =
      nextRows.length > MAX_TELEMETRY_ROWS
        ? nextRows.slice(nextRows.length - MAX_TELEMETRY_ROWS)
        : nextRows;
    this.reconcileSelectionWithRows();
    this.emit();
  };

  clearTelemetry = () => {
    this.telemetryColumns = [];
    this.telemetryRows = [];
    this.nextRowId = 1;
    this.packetSelection = {
      startIndex: 0,
      endIndex: 0,
      endFollowsLatest: true,
    };
    this.emit();
  };

  exportTelemetryCsv = () => {
    const columns = [...this.telemetryColumns];
    const header = ["id", "timestamp", ...columns];
    const rows = this.telemetryRows.map((row) => {
      const cells = [
        String(row.id),
        String(row.timestamp),
        ...columns.map((column) => this.toCsvCell(row.values[column])),
      ];
      return cells.join(",");
    });
    return [header.join(","), ...rows].join("\n");
  };

  importTelemetryCsv = (csvText: string) => {
    const lines = this.parseCsvLines(csvText);
    if (lines.length < 2) {
      throw new Error("CSV must include a header row and at least one data row.");
    }

    const header = lines[0].map((cell) => cell.trim());
    const idIndex = header.findIndex((h) => h.toLowerCase() === "id");
    const timestampIndex = header.findIndex((h) => h.toLowerCase() === "timestamp");
    if (timestampIndex < 0) {
      throw new Error("CSV header must include a timestamp column.");
    }

    const valueColumns = header
      .map((column, index) => ({ column, index }))
      .filter(
        ({ index, column }) =>
          index !== idIndex &&
          index !== timestampIndex &&
          column.length > 0,
      );

    const importedRows: ImportTelemetryRow[] = [];
    for (let lineIndex = 1; lineIndex < lines.length; lineIndex += 1) {
      const row = lines[lineIndex];
      const timestampCell = row[timestampIndex];
      const timestamp = Number(timestampCell);
      if (!Number.isFinite(timestamp)) {
        continue;
      }

      const values: Record<string, TelemetryValue> = {};
      valueColumns.forEach(({ column, index }) => {
        const raw = row[index] ?? "";
        values[column] = this.parseTelemetryCell(raw);
      });

      const idCell = idIndex >= 0 ? row[idIndex] : undefined;
      const id = idCell !== undefined && idCell !== "" ? Number(idCell) : undefined;
      importedRows.push({
        id: Number.isFinite(id) ? id : undefined,
        timestamp,
        values,
      });
    }

    if (importedRows.length === 0) {
      throw new Error("No valid packet rows found in CSV.");
    }

    this.replaceTelemetryRows(importedRows);
    return { importedCount: importedRows.length };
  };

  private replaceTelemetryRows = (rows: ImportTelemetryRow[]) => {
    const nextRows = rows.slice(-MAX_TELEMETRY_ROWS).map((row, index) => ({
      id: row.id ?? index + 1,
      timestamp: row.timestamp,
      values: { ...row.values },
    }));

    const columnSet = new Set<string>();
    nextRows.forEach((row) => {
      Object.keys(row.values).forEach((column) => {
        if (column.trim().length > 0) columnSet.add(column);
      });
    });

    this.telemetryColumns = Array.from(columnSet);
    this.telemetryRows = nextRows;
    this.nextRowId =
      (nextRows.reduce((maxId, row) => Math.max(maxId, row.id), 0) || 0) + 1;
    this.reconcileSelectionWithRows();
    this.emit();
  };

  private emit = () => {
    this.rebuildSnapshot();
    this.listeners.forEach((listener) => listener());
  };

  private rebuildSnapshot = () => {
    this.snapshot = {
      connectionStatus: this.connectionStatus,
      ipAddress: this.ipAddress,
      connectionMessage: this.connectionMessage,
      telemetryColumns: [...this.telemetryColumns],
      telemetryRows: this.telemetryRows.map((row) => ({
        id: row.id,
        timestamp: row.timestamp,
        values: { ...row.values },
      })),
      packetSelection: { ...this.packetSelection },
      streamPaused: this.streamPaused,
    };
  };

  private reconcileSelectionWithRows = () => {
    const lastIndex = Math.max(0, this.telemetryRows.length - 1);
    let startIndex = Math.min(Math.max(this.packetSelection.startIndex, 0), lastIndex);
    const endIndex = this.packetSelection.endFollowsLatest
      ? lastIndex
      : Math.min(Math.max(this.packetSelection.endIndex, 0), lastIndex);

    if (startIndex > endIndex) {
      startIndex = endIndex;
    }

    this.packetSelection = {
      startIndex,
      endIndex,
      endFollowsLatest: this.packetSelection.endFollowsLatest,
    };
  };

  private findNearestRowIndexForTimestamp = (timestamp: number): number | null => {
    if (!Number.isFinite(timestamp) || this.telemetryRows.length === 0) {
      return null;
    }

    let nearestIndex = 0;
    let nearestDistance = Math.abs(this.telemetryRows[0].timestamp - timestamp);

    for (let i = 1; i < this.telemetryRows.length; i += 1) {
      const distance = Math.abs(this.telemetryRows[i].timestamp - timestamp);
      if (distance < nearestDistance) {
        nearestDistance = distance;
        nearestIndex = i;
      }
    }

    return nearestIndex;
  };

  private startMockStream = () => {
    this.stopMockStream();

    this.mockStreamTimer = window.setInterval(() => {
      const now = Date.now();
      this.addTelemetrySample(this.createRandomTelemetryDatums(now), now);
    }, 1000);
  };

  private startPolling = (connectTarget: string) => {
    this.stopPolling();

    let url = connectTarget;
    // Basic check for port: if it looks like an IP or hostname without a colon (IPV4)
    // Note: IPv6 is complicated, but for FTC 192.168.43.1 is standard.
    if (!url.includes(":")) {
      url = `${url}:12345`;
    }
    if (!url.startsWith("http")) {
      url = `http://${url}`;
    }

    const endpoint = `${url}/telemetry`;
    this.pollingAbortController = new AbortController();
    const signal = this.pollingAbortController.signal;

    const poll = async () => {
      // If the parent controller is aborted, stop.
      if (signal.aborted) return;

      if (this.streamPaused) {
        // If paused, just check back in 500ms
        this.pollingTimer = window.setTimeout(poll, 500);
        return;
      }

      try {
        const fetchController = new AbortController();
        const timeoutId = window.setTimeout(() => fetchController.abort(), 2000);

        // Listen to the parent abort to cancel the child fetch too
        const onAbort = () => fetchController.abort();
        signal.addEventListener("abort", onAbort);

        try {
          const res = await fetch(endpoint, {
            signal: fetchController.signal,
            method: "GET",
            // mode: "cors", // Default is cors
          });
          window.clearTimeout(timeoutId);

          if (!res.ok) {
            throw new Error(`HTTP ${res.status}`);
          }

          const text = await res.text();
          const datums = this.toTelemetryDatums(text);
          if (datums && datums.length > 0) {
            this.addTelemetrySample(datums, Date.now());
          }

          if (this.connectionStatus !== "connected") {
            this.connectionStatus = "connected";
            this.connectionMessage = `Connected to ${connectTarget}`;
            this.emit();
          }
        } finally {
          signal.removeEventListener("abort", onAbort);
          window.clearTimeout(timeoutId);
        }

      } catch (err: unknown) {
        if (signal.aborted) return;

        // If we were connected, stay connected but maybe log?
        // If we are connecting, stay connecting.
      }

      if (!signal.aborted) {
        // Poll at 20Hz (50ms)
        this.pollingTimer = window.setTimeout(poll, 50);
      }
    };

    poll();
  };

  private stopPolling = () => {
    if (this.pollingAbortController) {
      this.pollingAbortController.abort();
      this.pollingAbortController = null;
    }
    if (this.pollingTimer !== null) {
      window.clearTimeout(this.pollingTimer);
      this.pollingTimer = null;
    }
  };



  private toTelemetryDatums = (payload: unknown): TelemetryDatum[] | null => {
    if (typeof payload !== "string") {
      return null;
    }

    try {
      const parsed = JSON.parse(payload) as unknown;

      if (Array.isArray(parsed)) {
        if (
          parsed.every(
            (entry) =>
              typeof entry === "object" &&
              entry !== null &&
              "name" in entry &&
              "value" in entry,
          )
        ) {
          return parsed as TelemetryDatum[];
        }
      }

      if (typeof parsed === "object" && parsed !== null) {
        const asRecord = parsed as Record<string, unknown>;

        if (Array.isArray(asRecord.telemetry)) {
          const telemetry = asRecord.telemetry;
          if (
            telemetry.every(
              (entry) =>
                typeof entry === "object" &&
                entry !== null &&
                "name" in entry &&
                "value" in entry,
            )
          ) {
            return telemetry as TelemetryDatum[];
          }
        }

        const datums = Object.entries(asRecord)
          .filter(([, value]) =>
            ["string", "number", "boolean"].includes(typeof value),
          )
          .map(([name, value]) => ({
            name,
            value: value as TelemetryValue,
          }));

        if (datums.length > 0) {
          return datums;
        }
      }
    } catch {
      return null;
    }

    return null;
  };

  private createRandomTelemetryDatums = (timestamp: number): TelemetryDatum[] => {
    const phase = timestamp / 1000;
    const headingDeg = Number((Math.random() * 360).toFixed(2));
    const xIn = Number((Math.sin(phase * 0.8) * 52 + Math.sin(phase * 0.17) * 12).toFixed(2));
    const yIn = Number((Math.cos(phase * 0.65) * 54 + Math.cos(phase * 0.13) * 10).toFixed(2));
    const flywheelSpeedRpm = Math.round(Math.random() * 2000);
    const deflectorAngle = Number(Math.random().toFixed(3));
    const yawAngleDeg = Number((Math.random() * 540 - 270).toFixed(2));
    const ballCount = Math.floor(Math.random() * 4);

    const batteryVoltage = Number(
      (12.4 + Math.sin(phase / 7) * 0.45 + (Math.random() - 0.5) * 0.06).toFixed(2),
    );
    const loopTimeMs = Math.round(14 + Math.random() * 10);
    const drivetrainSpeedInPerSec = Number((Math.random() * 85).toFixed(2));
    const intakeCurrentA = Number((2 + Math.random() * 9).toFixed(2));
    const shooterTempC = Number((36 + Math.random() * 18).toFixed(1));
    const targetVisible = Math.random() > 0.35;

    return [
      { name: "headingDeg", value: headingDeg },
      { name: "xIn", value: xIn },
      { name: "yIn", value: yIn },
      { name: "flywheelSpeedRpm", value: flywheelSpeedRpm },
      { name: "deflectorAngle", value: deflectorAngle },
      { name: "yawAngleDeg", value: yawAngleDeg },
      { name: "ballCount", value: ballCount },
      { name: "loopTimeMs", value: loopTimeMs },
      { name: "batteryVoltage", value: batteryVoltage },
      { name: "drivetrainSpeedInPerSec", value: drivetrainSpeedInPerSec },
      { name: "intakeCurrentA", value: intakeCurrentA },
      { name: "shooterTempC", value: shooterTempC },
      { name: "targetVisible", value: targetVisible },
    ];
  };

  private stopMockStream = () => {
    if (this.mockStreamTimer === null) return;
    window.clearInterval(this.mockStreamTimer);
    this.mockStreamTimer = null;
  };

  private clearConnectTimer = () => {
    if (this.connectTimer === null) return;
    window.clearTimeout(this.connectTimer);
    this.connectTimer = null;
  };

  private toCsvCell = (value: TelemetryValue | undefined) => {
    const raw = value === undefined ? "" : String(value);
    if (raw.includes(",") || raw.includes("\"") || raw.includes("\n")) {
      return `"${raw.replaceAll("\"", "\"\"")}"`;
    }
    return raw;
  };

  private parseTelemetryCell = (raw: string): TelemetryValue => {
    const trimmed = raw.trim();
    if (trimmed.toLowerCase() === "true") return true;
    if (trimmed.toLowerCase() === "false") return false;
    if (/^-?\d+(\.\d+)?$/.test(trimmed)) return Number(trimmed);
    return raw;
  };

  private parseCsvLines = (csvText: string): string[][] => {
    const rows: string[][] = [];
    let row: string[] = [];
    let cell = "";
    let inQuotes = false;

    for (let i = 0; i < csvText.length; i += 1) {
      const char = csvText[i];
      const next = csvText[i + 1];

      if (char === "\"") {
        if (inQuotes && next === "\"") {
          cell += "\"";
          i += 1;
        } else {
          inQuotes = !inQuotes;
        }
        continue;
      }

      if (!inQuotes && char === ",") {
        row.push(cell);
        cell = "";
        continue;
      }

      if (!inQuotes && (char === "\n" || char === "\r")) {
        if (char === "\r" && next === "\n") {
          i += 1;
        }
        row.push(cell);
        if (row.some((entry) => entry.length > 0)) {
          rows.push(row);
        }
        row = [];
        cell = "";
        continue;
      }

      cell += char;
    }

    if (cell.length > 0 || row.length > 0) {
      row.push(cell);
      if (row.some((entry) => entry.length > 0)) {
        rows.push(row);
      }
    }

    return rows;
  };
}

export const robotTelemetryManager = new RobotTelemetryManager();
